<template>
  <b-container fluid class="d-flex flex-column py-3">
    <b-row class="mb-3">
      <b-col>{{ compareNm }}</b-col>
    </b-row>
    <template v-if="visibleCompare">
      <b-form-row class="mb-2">
        <b-col
          cols="4"
          class="text-center text-truncate"
          v-for="(headerField, index) in headerFields"
          :key="headerField.key"
        >
          <label class="d-block bg-secondary text-light rounded-pill small mb-1">
            {{ headerField.label }}
          </label>
          <span>{{ item[`headerFormatValueNo${index + 1}`] }}</span>
        </b-col>
        <b-col cols="4" class="text-center text-truncate ml-auto">
          <label class="d-block bg-secondary text-light rounded-pill small mb-1">予定/実績</label>
          <span class="text-truncate"
            >{{ item.orderCount }}&nbsp;/&nbsp;{{ item.resultCount }}</span
          >
        </b-col>
      </b-form-row>
      <b-table
        sticky-header
        no-border-collapse
        thead-tr-class="small"
        tbody-tr-class="h5"
        :items="item.details"
        :fields="detailFields"
      >
        <!-- 照合実績 -->
        <template #cell(compareFlg)="data">
          <span v-if="data.item.completeSts === '4'" class="text-success font-weight-bold">RD</span>
          <span v-else-if="data.value === 1" class="text-danger font-weight-bold">NG</span>
          <span
            v-else-if="data.value === 0 && data.item.shortFlg === 0"
            class="text-primary font-weight-bold"
            >OK</span
          >
          <span v-else-if="data.item.shortFlg === 1" class="font-weight-bold">欠品</span>
          <span v-else-if="data.value === 9">未</span>
        </template>
        <!-- 照合日時 -->
        <template #cell(compareDt)="data">
          <p class="small mb-0">
            {{ data.value ? data.value.split(' ')[0].substring(5).replace('-', '/') : '' }}
          </p>
          <p class="small mb-0">{{ data.value ? data.value.split(' ')[1].substring(0, 5) : '' }}</p>
        </template>
      </b-table>
    </template>
    <b-row v-if="visibleProcButtons">
      <b-col>
        <b-dropdown
          :text="
            buttonMode === 1
              ? '欠品登録'
              : buttonMode === 2
              ? '欠品解除'
              : buttonMode === 3
              ? '予定削除'
              : buttonMode === 4
              ? '強制完了'
              : 'エラー解除'
          "
          block
          split
          dropup
          split-variant="danger"
          @click="onClickProc"
        >
          <b-dropdown-item v-if="visibleShortButton" @click="buttonMode = 1"
            >欠品登録</b-dropdown-item
          >
          <b-dropdown-item v-if="visibleReleaseButton" @click="buttonMode = 2"
            >欠品解除</b-dropdown-item
          >
          <b-dropdown-item v-if="visibleDeleteButton" @click="buttonMode = 3"
            >予定削除</b-dropdown-item
          >
          <b-dropdown-item v-if="visibleForceButton" @click="buttonMode = 4"
            >強制完了</b-dropdown-item
          >
          <b-dropdown-item v-if="visibleCancelButton" @click="buttonMode = 5"
            >エラー解除</b-dropdown-item
          >
        </b-dropdown>
      </b-col>
    </b-row>
  </b-container>
</template>

<script>
import {
  putCompareResultReleaseAPI,
  getCompareResultAPI,
  putCompareResultForceAPI,
  deleteCompareOrderAPI,
  putCompareResultCancelAPI,
  putCompareResultShortAPI
} from '@/api';
import { getCompareHeaderFields, getCompareDetailToFields, convertItemFormat } from '@/compare';
import { completeSts, historyProcMode } from '@/constants';

export default {
  name: 'CompareHistoryDetail',
  data() {
    return {
      buttonMode: null, // 1:欠品登録、2:欠品解除、3:予定削除、4:強制完了、5:エラー解除
      compareNm: null, // 読取ルール名
      headerFields: [], // ヘッダ項目リスト
      detailFields: [], // 明細項目リスト
      item: {
        // 照合画面情報
        compareOrderNo: 0, //  照合予定NO
        compareResultNo: 0, //  照合実績NO
        orderCount: 0, //  予定件数
        resultCount: 0, //  実績件数
        details: [] //  明細リスト
      }
    };
  },
  async mounted() {
    // 画面を初期化
    this.$emit('initView', { viewId: this.$options.name, useToolButtons: false });

    const read = this.$store.getters.currentRead;
    if (read) {
      // 読取ルール名取得
      this.compareNm = read.readNm;

      // 照合予定情報取得
      await this.getCompareResult(
        this.$route.params['compareOrderNo'],
        this.$route.params['compareResultNo'],
        this.$store.getters.currentCompare
      );

      if (this.item['completeSts'] === completeSts.NO_RESULT)
        this.buttonMode = historyProcMode.REGIST_SHORT;
      else if (this.item['completeSts'] === completeSts.PROCESSING)
        this.buttonMode = historyProcMode.REGIST_SHORT;
      else if (this.item['completeSts'] === completeSts.COMPLETE_OK && this.item['shortFlg'] === 1)
        this.buttonMode = historyProcMode.RELEASE_SHORT;
      else if (this.item['completeSts'] === completeSts.COMPLETE_NG)
        this.buttonMode = historyProcMode.CANCEL_ERROR;
    }
  },
  computed: {
    /**
     * 照合表示状態
     */
    visibleCompare: function () {
      return this.item['compareOrderNo'];
    },
    /**
     * 処理ボタン表示状態
     */
    visibleProcButtons: function () {
      return (
        this.item['completeSts'] === completeSts.NO_RESULT ||
        this.item['completeSts'] === completeSts.PROCESSING ||
        (this.item['completeSts'] === completeSts.COMPLETE_OK && this.item['shortFlg'] === 1) ||
        this.item['completeSts'] === completeSts.COMPLETE_NG
      );
    },
    /**
     * 欠品登録ボタン表示状態
     */
    visibleShortButton: function () {
      return (
        this.item['completeSts'] === completeSts.NO_RESULT ||
        this.item['completeSts'] === completeSts.PROCESSING
      );
    },
    /**
     * 欠品解除ボタン表示状態
     */
    visibleReleaseButton: function () {
      return this.item['completeSts'] === completeSts.COMPLETE_OK && this.item['shortFlg'] === 1;
    },
    /**
     * 予定削除ボタン表示状態
     */
    visibleDeleteButton: function () {
      return this.item['compareResultNo'] === 0;
    },
    /**
     * 強制完了ボタン表示状態
     */
    visibleForceButton: function () {
      return this.item['completeSts'] === completeSts.PROCESSING;
    },
    /**
     * エラー解除ボタン表示状態
     */
    visibleCancelButton: function () {
      return this.item['completeSts'] === completeSts.COMPLETE_NG;
    }
  },
  methods: {
    /**
     * 欠品登録/欠品解除/強制完了/予定削除/エラー解除ボタン
     */
    onClickProc: async function () {
      const orderNo = this.item['compareOrderNo'];
      const resultNo = this.item['compareResultNo'];
      let ret = null;
      let proc = '';
      switch (this.buttonMode) {
        case historyProcMode.REGIST_SHORT: // 欠品登録
          ret = await putCompareResultShortAPI(orderNo, resultNo);
          proc = '欠品登録';
          break;
        case historyProcMode.RELEASE_SHORT: // 欠品解除
          ret = await putCompareResultReleaseAPI(orderNo, resultNo);
          proc = '欠品解除';
          break;
        case historyProcMode.DELETE_ORDER: // 予定削除
          // 照合予定削除API
          ret = await deleteCompareOrderAPI(orderNo);
          proc = '予定削除';
          break;
        case historyProcMode.UPDATE_FORCE: // 強制完了
          // 照合実績強制完了API
          ret = await putCompareResultForceAPI(orderNo, resultNo);
          proc = '実績強制完了';
          break;
        case historyProcMode.CANCEL_ERROR: // エラー解除
          // 照合実績エラー解除API
          ret = await putCompareResultCancelAPI(orderNo, resultNo);
          proc = 'エラー解除';
      }

      if (!ret) {
        this.$store.commit('setMessage', `通信エラー(${proc})`);
        return;
      }

      // 前画面へ
      this.$store.commit('decrementHistoryCount');
      this.$router.back();
    },
    /**
     * 欠品解除ボタン
     */
    onClickRelease: async function () {
      const ret = await putCompareResultReleaseAPI(
        this.item['compareOrderNo'],
        this.item['compareResultNo']
      );
      if (!ret) {
        this.$store.commit('setMessage', '通信エラー(予定欠品解除更新)');
        return;
      }

      // 前画面へ
      this.$store.commit('decrementHistoryCount');
      this.$router.back();
    },
    /**
     * 照合実績情報取得
     * @param {number} compareOrderNo 照合予定NO
     * @param {number} compareResultNo 照合実績NO
     * @param {object} compare 照合情報(details:明細付き)
     */
    getCompareResult: async function (compareOrderNo, compareResultNo, compare) {
      // ヘッダ項目セット
      this.headerFields = getCompareHeaderFields(compare);

      // 明細項目セット
      const detailFields = getCompareDetailToFields(compare);
      detailFields.push({ key: 'compareFlg', label: '照合' });
      this.detailFields = detailFields.map(function (x) {
        return { key: x.key, label: x.label, thClass: 'p-1', tdClass: 'px-1' };
      });
      this.detailFields.push({
        key: 'compareDt',
        label: '日時',
        thClass: 'p-1',
        tdClass: 'p-1'
      });

      // 照合実績情報取得API
      const ret = await getCompareResultAPI(compareOrderNo, compareResultNo);
      if (!ret) {
        this.$store.commit('setMessage', '通信エラー(照合実績取得)');
        return;
      }

      this.item = ret.data;
      convertItemFormat(compare, this.item);
    }
  }
};
</script>

<style>
div.container-fluid {
  height: 100%;
}
.b-table-sticky-header {
  height: 100%;
  max-height: none !important;
  -webkit-flex: 1 1 0;
  -ms-flex: 1 1 0;
  flex: 1 1 0;
}
</style>
